function VALUE_ITERATION(S, A, P, R, gamma, theta):
 // Initialize value function
 V = zeros(|S|)

 repeat
 delta = 0
 for each state s in S:
 v = V(s)
 // Bellman optimality update
 V(s) = max_a sum_{s'} P(s'|s,a) * (R(s,a,s') + gamma * V(s'))
 delta = max(delta, abs(v - V(s)))
 until delta < theta

 // Extract optimal policy
 for each state s in S:
 pi(s) = argmax_a sum_{s'} P(s'|s,a) * (R(s,a,s') + gamma * V(s'))

 return V, pi

function POLICY_EVALUATION(pi, S, A, P, R, gamma, theta):
 // Initialize value function
 V = zeros(|S|)

 repeat
 delta = 0
 for each state s in S:
 v = V(s)
 // Bellman equation for given policy
 V(s) = sum_a pi(a|s) * sum_{s'} P(s'|s,a) * (R(s,a,s') + gamma * V(s'))
 delta = max(delta, abs(v - V(s)))
 until delta < theta

 return V

function POLICY_ITERATION(S, A, P, R, gamma, theta):
 // Initialize random policy
 pi = random_policy(|S|, |A|)

 repeat
 // Step 1: Policy Evaluation
 V = POLICY_EVALUATION(pi, S, A, P, R, gamma, theta)

 // Step 2: Policy Improvement
 policy_stable = TRUE
 for each state s in S:
 old_action = pi(s)
 // Greedy policy improvement
 pi(s) = argmax_a sum_{s'} P(s'|s,a) * (R(s,a,s') + gamma * V(s'))
 if old_action != pi(s):
 policy_stable = FALSE
 until policy_stable = TRUE

 return pi, V // Returns optimal policy and value function

